// Get the single account record correctly
const account = $input.first().json;

const billingFields = [
  'Billing_Street',
  'Billing_City',
  'Billing_State',
  'Billing_Country',
  'Billing_Code'
];

const missingBillingFields = billingFields.filter(field => {
  const value = account[field];
  return (
    value === null ||
    value === undefined ||
    (typeof value === 'string' && value.trim() === '')
  );
});

return [{
  json: {
    accountId: account.id,
    accountName: account.Account_Name,
    missingBillingFields,
    isBillingComplete: missingBillingFields.length === 0
  }
}];

// Mandatory fields for Closed-Won deals
const mandatoryFields = [
  "Service_Division",
  "Service_Type",
  "Expected_Start_Date",
  "Expected_End_Date",
  "Key_Milestones",
  "Payment_Terms",
  "Scope_Document",
  "Closing_Date",
  "Amount",
  "Estimated_Delivery_time_shared",
  "Engagement_Type"
];

const outputItems = [];

for (const item of $input.all()) {
  const deal = item.json;

  // Only Closed-Won deals
  if (deal.Stage !== "Closed- Won") continue;

  if (!deal.Account_Name || !deal.Account_Name?.id) continue;

  const missingFields = mandatoryFields.filter(field => {
    const value = deal[field];
    if (value === null || value === undefined) return true;
    if (typeof value === "string" && value.trim() === "") return true;
    if (Array.isArray(value) && value.length === 0) return true;
    return false;
  });

  outputItems.push({
    json: {
      ...deal,
      missingFields,
      isComplete: missingFields.length === 0,
      dealCategory: missingFields.length === 0 ? "COMPLETE" : "MISSING"
    }
  });
}

// ✅ Single-output, n8n-safe return
return outputItems;

// Get the current deal from the loop iteration
const deal = $('Loop Over Items').first().json;

// Get account data from previous node

return [{
  json: {
    owner: deal.Owner,
    dealName: deal.Deal_Name,
    dealMissingFields: deal.missingFields,
    billingMissingFields: $json.missingBillingFields,
    accountName: $json.accountName
  }
}];

// 1. Get all items entering the node
const items = $input.all();

// 2. Map over every item to check its billing details
return items.map(item => {
  const account = item.json;

  const billingFields = [
    'Billing_Street',
    'Billing_City',
    'Billing_State',
    'Billing_Country',
    'Billing_Code'
  ];

  // Check which fields are missing or just empty strings
  const missingBillingDetails = billingFields.filter(field => {
    const value = account[field];
    return (
      value === null ||
      value === undefined ||
      (typeof value === 'string' && (value.trim() === '' ))
    );
  });

  // Return the item in the format you prefer
  return {
    json: {
      Account_Name: account.Account_Name,
      Account_Id: account.id,
      Missing_Billing_Details: missingBillingDetails,
      Is_Billing_Complete: missingBillingDetails.length === 0,
      // We keep the original billing data so it can be used later
      Billing_Street: account.Billing_Street,
      Billing_City: account.Billing_City,
      Billing_State: account.Billing_State,
      Billing_Country: account.Billing_Country,
      Billing_Code: account.Billing_Code
    }
  };
});

// 1. Get ALL items entering this node (the billing check results)
const inputItems = $input.all();

// 2. Get the master list of all deals once
const allDeals = $("Filter Deal Stage").all();

// 3. Loop through every billing check item
return inputItems.map(item => {
  const billingInfo = item.json;
  const accountId = billingInfo.Account_Id;

  // Find the specific deal that matches this account ID
  const dealItem = allDeals.find(
    i => i.json.Account_Name?.id === accountId
  );

  let owner, dealName, serviceDivision, dealId;

  if (dealItem) {
    owner = dealItem.json.Owner;
    dealName = dealItem.json.Deal_Name;
    serviceDivision = dealItem.json.Service_Division?.toLowerCase();
    dealId = dealItem.json.id;
  }

  // Return a consolidated object for every item
  return {
    json: {
      Owner_Name: owner?.name || '-',
      Owner_Email: owner?.email || '-',
      Deal_Name: dealName || '-',
      Deal_Id: dealId || '-',
      Account_Name: billingInfo.Account_Name,
      Account_Id: accountId,
      Service_Division: serviceDivision || '-',
      Billing_Missing_Fields: billingInfo.Missing_Billing_Details,
      Is_Billing_Complete: billingInfo.Is_Billing_Complete
    }
  };
});

const items = $input.all();

const groupedByEmail = {};

for (const item of items) {
  const {
    owner,
    dealName,
    accountName,
    billingMissingfields
  } = item.json;

  const email = owner.email;

  if (!groupedByEmail[email]) {
    groupedByEmail[email] = {
      email,
      ownerName: owner.name,
      rows: []
    };
  }

  groupedByEmail[email].rows.push({
    dealName,
    accountName,
    billingMissingfields: billingMissingfields.length
      ? billingMissingfields.join(", ")
      : "—"
  });
}

// Convert object → n8n items
return Object.values(groupedByEmail).map(group => ({
  json: group
}));

const items = $input.all();
const grouped = {};

for (const item of items) {
  // 1. Update these variable names to match the output of your 
  // "Consolidate deal and billing details" node
  const {
    Owner_Name,
    Owner_Email,
    Deal_Name,
    Deal_Id,
    Account_Name,
    Account_Id,
    Service_Division,
    Billing_Missing_Fields
  } = item.json;

  // 2. Safety guard using the new key name
  if (!Owner_Email) continue;

  const service = Service_Division || 'unknown';

  // 3. Create the grouping key (Owner + Service)
  const groupKey = `${Owner_Email}__${service}`;

  if (!grouped[groupKey]) {
    grouped[groupKey] = {
      Owner_Email: Owner_Email,
      Owner_Name: Owner_Name,
      Service_Division: service,
      Rows: [] // Capitalized to match your preference
    };
  }

  // 4. Push the deal info into the rows array
  grouped[groupKey].Rows.push({
    Deal_Name: Deal_Name,
    Deal_Id: Deal_Id,
    Account_Name: Account_Name,
    Account_Id: Account_Id,
    Billing_Missing_Fields: Billing_Missing_Fields?.length
      ? Billing_Missing_Fields.join(', ')
      : '—'
  });
}

// 5. Convert the grouped object back into n8n items
return Object.values(grouped).map(group => ({
  json: group
}));

